{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/randomizer.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  # 乱数生成器\n  class Randomizer\n    UPPER_LIMIT_DICE_TIMES = 200\n    UPPER_LIMIT_DICE_SIDES = 10000\n\n    UPPER_LIMIT_RANDS = 10000\n\n    def initialize\n      @rand_results = []\n      @detailed_rand_results = []\n    end\n\n    # @return [Array<Array<(Integer, Integer)>>] ダイスの出目一覧\n    attr_reader :rand_results\n\n    # @return [Array<DetailedRandResult>]\n    attr_reader :detailed_rand_results\n\n    # 実行したダイスロールの詳細\n    # @!attribute [rw] kind\n    #   @return [Symbol]\n    # @!attribute [rw] sides\n    #   @return [Integer] ダイスロールしたダイスの面数\n    # @!attribute [rw] value\n    #   @return [Integer] 値\n    DetailedRandResult = Struct.new(:kind, :sides, :value)\n\n    # 複数個のダイスを振る\n    #\n    # @param times [Integer] 振るダイスの個数\n    # @param sides [Integer] ダイスの面数\n    # @return [Array<Integer>] ダイスの出目一覧\n    def roll_barabara(times, sides)\n      if @rand_results.size + times > UPPER_LIMIT_RANDS\n        raise TooManyRandsError\n      end\n\n      if times <= 0 || times > UPPER_LIMIT_DICE_TIMES\n        return []\n      end\n\n      Array.new(times) { roll_once(sides) }\n    end\n\n    # 複数個のダイスを振って、その合計を求める\n    #\n    # @param times [Integer] 振るダイスの個数\n    # @param sides [Integer] ダイスの面数\n    # @return [Integer] 出目の合計\n    def roll_sum(times, sides)\n      roll_barabara(times, sides).sum()\n    end\n\n    # 1回だけダイスロールを行う\n    #\n    # @param sides [Integer] ダイスの面数\n    # @return [Integer] 1以上 *sides* 以下の値のいずれか\n    def roll_once(sides)\n      if sides <= 0 || sides > UPPER_LIMIT_DICE_SIDES\n        return 0\n      end\n\n      dice = rand_inner(sides)\n      push_to_detail(:normal, sides, dice)\n\n      return dice\n    end\n\n    # ダイス表などでindexを参照する用のダイスロール\n    # @param sides [Integer]\n    # @return [Integer] 0以上 *sides* 未満の整数\n    def roll_index(sides)\n      roll_once(sides) - 1\n    end\n\n    # 十の位をd10を使って決定するためのダイスロール\n    # @return [Integer] 0以上90以下で10の倍数となる整数\n    def roll_tens_d10()\n      # rand_innerの戻り値を10倍すればすむ話なのだが、既存のテストとの互換性の為に処理をする\n      dice = rand_inner(10)\n      if dice == 10\n        dice = 0\n      end\n\n      ret = dice * 10\n\n      push_to_detail(:tens_d10, 10, ret)\n      return ret\n    end\n\n    # d10を0~9として扱うダイスロール\n    # @return [Integer] 0以上9以下の整数\n    def roll_d9()\n      dice = rand_inner(10) - 1\n\n      push_to_detail(:d9, 10, dice)\n      return dice\n    end\n\n    # D66のダイスロールを行う\n    # @param sort_type [Symbol] BCDice::D66SortType\n    # @return [Integer]\n    def roll_d66(sort_type)\n      dice_list = Array.new(2) { roll_once(6) }\n\n      case sort_type\n      when D66SortType::ASC\n        dice_list.sort!\n      when D66SortType::DESC\n        dice_list.sort!.reverse!\n      end\n\n      return dice_list[0] * 10 + dice_list[1]\n    end\n\n    private\n\n    # @param sides [Integer]\n    # @return [Integer] 1以上sides以下の整数\n    def rand_inner(sides)\n      if @rand_results.size >= UPPER_LIMIT_RANDS\n        raise TooManyRandsError\n      end\n\n      dice = random(sides)\n\n      @rand_results << [dice, sides]\n      return dice\n    end\n\n    # モックで上書きする用\n    # @param sides [Integer]\n    # @return [Integer] 1以上sides以下の整数\n    def random(sides)\n      Kernel.rand(sides) + 1\n    end\n\n    # @param [Symbol] kind\n    # @param [Integer] sides\n    # @param [Integer] value\n    def push_to_detail(kind, sides, value)\n      detail = DetailedRandResult.new(kind, sides, value)\n      @detailed_rand_results.push(detail)\n    end\n  end\n\n  class TooManyRandsError < StandardError; end\nend\n"], :names=>["<main>", "<module:BCDice>", "<class:Randomizer>", "200", "10000", "initialize", "@rand_results", "@detailed_rand_results", "self", "attr_reader", "Struct", "new", "roll_barabara", "times", "sides", ">", "+", "size", "UPPER_LIMIT_RANDS", "raise", "TooManyRandsError", "<=", "0", "UPPER_LIMIT_DICE_TIMES", "Array", "block in roll_barabara", "block (2 levels) in roll_barabara", "roll_once", "roll_sum", "sum", "UPPER_LIMIT_DICE_SIDES", "dice", "rand_inner", "push_to_detail", "roll_index", "-", "1", "roll_tens_d10", "10", "ret", "*", "roll_d9", "roll_d66", "sort_type", "dice_list", "2", "block in roll_d66", "block (2 levels) in roll_d66", "6", "D66SortType::ASC", "D66SortType", "$ret_or_1", "sort!", "D66SortType::DESC", "reverse!", "[]", "private", ">=", "random", "<<", "Kernel", "rand", "kind", "value", "detail", "DetailedRandResult", "push", "<class:TooManyRandsError>", "StandardError"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;;IAEEC;IAAAA;;MAAAA;;AAAAA;;MACE,kDAAyBC,GAAzB;MACA,kDAAyBC,KAAzB;MAEA,6CAAoBA,KAApB;;AAEAC,MAAAA,0BAAAA,sBAAAA;AAAAA,QAAAA;;;QACEC,oBAAgB;QAChBD,OAAAE,CAAAA,6BAAyB,EAAzBA;MAFFF,CAAAA;MAMAG,IAAAC,aAAAA,CAAY,cAAZA;MAGAD,IAAAC,aAAAA,CAAY,uBAAZA;MASA,8CAAqBC,YAAMC,KAAAA,CAAK,MAAX,EAAkB,OAAlB,EAA0B,OAApBA,CAA3B;;AAOAC,MAAAA,6BAAAA,yBAAkBC,KAAD,EAAQC,KAAzBF;AAAAA,QAAAA;;;QACE,IAAA,QAA8BG,OAARC,SAAnBV,iBAAaW,MAAAA,CAAAA,CAAMD,EAAEH,KAAFG,CAAQD,EAAEG,uBAAFH,CAA9B,CAAA;UACEP,IAAAW,OAAAA,CAAMC,uBAAND;QADF;QAIA,IAAG,CAAA,QAAME,OAANR,KAAMQ,EAAGC,CAAHD,CAAN,CAAA,IAAA,CAAA,QAAoBN,OAANF,KAAME,EAAEQ,4BAAFR,CAApB,CAAA,CAAA,CAAH;UACE,OAAO;QADT;QAIAH,OAAKD,MAALa,WAAKb,OAAAA,EAAAA,CAAKE,KAALF,CAAAA,EAALc,aAAAA,EAAAC;;UAAmBA,OAAAlB,IAAAmB,WAAAA,CAAUb,KAAVa,CAAnBF,CAAAA,GAAAA,SAAAA,CAAKd;MATPC,CAAAA;;AAiBAgB,MAAAA,wBAAAA,oBAAaf,KAAD,EAAQC,KAApBc;AAAAA,QAAAA;;QACEA,OAAApB,IAAAI,eAAAA,CAAcC,KAAd,EAAqBC,KAArBF,CAA2BiB,KAAAA,CAAAA;MAD7BD,CAAAA;;AAQAD,MAAAA,yBAAAA,qBAAcb,KAAda;AAAAA,QAAAA;;;QACE,IAAG,CAAA,QAAMN,OAANP,KAAMO,EAAGC,CAAHD,CAAN,CAAA,IAAA,CAAA,QAAoBN,OAAND,KAAMC,EAAEe,4BAAFf,CAApB,CAAA,CAAA,CAAH;UACE,OAAOO;QADT;QAIAS,OAAOvB,IAAAwB,YAAAA,CAAWlB,KAAXkB;QACPxB,IAAAyB,gBAAAA,CAAe,QAAf,EAAwBnB,KAAxB,EAA+BiB,IAA/BE;QAEA,OAAOF;MARTJ,CAAAA;;AAcAO,MAAAA,0BAAAA,sBAAepB,KAAfoB;AAAAA,QAAAA;;QACEA,OAAiBC,UAAjB3B,IAAAmB,WAAAA,CAAUb,KAAVa,CAA